import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import Navbar from "./components/Navbar";
import Landing from "./pages/Landing";

import AuthorityPage from "./pages/Authority";
import BinPage from "./pages/Bin";
import DriverPage from "./pages/Driver";
import UserPage from "./pages/User";
import VehiclePage from "./pages/Vehicle";

function DashboardLayout({ children }) {
  return (
    <div className="dashboard-shell">
      <main className="dashboard-container">{children}</main>
    </div>
  );
}

function App() {
  return (
    <Router>
      <Navbar />

      <div className="main-content">
        <Routes>
          {/* PUBLIC WEBSITE */}
          <Route path="/" element={<Landing />} />

          {/* DASHBOARD */}
          <Route
            path="/authority"
            element={
              <DashboardLayout>
                <AuthorityPage />
              </DashboardLayout>
            }
          />
          <Route
            path="/bin"
            element={
              <DashboardLayout>
                <BinPage />
              </DashboardLayout>
            }
          />
          <Route
            path="/driver"
            element={
              <DashboardLayout>
                <DriverPage />
              </DashboardLayout>
            }
          />
          <Route
            path="/user"
            element={
              <DashboardLayout>
                <UserPage />
              </DashboardLayout>
            }
          />
          <Route
            path="/vehicle"
            element={
              <DashboardLayout>
                <VehiclePage />
              </DashboardLayout>
            }
          />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
